window.BIBLE = window.BIBLE || {};
window.BIBLE["Philippians"] = {"1":{"chapter":"1","title":"TO LIVE IS CHRIST, TO DIE IS GAIN","verses":{"1":{"text":"Paul and Timotheus, the servants of Jesus Christ, to all the saints in Christ Jesus which are at Philippi, with the bishops and deacons:","ref":"Philippians 1:1","synthesized":"Paul and Timothy, servants of Christ Jesus,  To all the saints in Christ Jesus at Philippi, together with the overseers and deacons:","sources":{"KJV":{"text":"Paul and Timotheus, the servants of Jesus Christ, to all the saints in Christ Jesus which are at Philippi, with the bishops and deacons:"},"BSB":{"text":"Paul and Timothy, servants of Christ Jesus,  To all the saints in Christ Jesus at Philippi, together with the overseers and deacons:"}},"definableWords":["servants","Christ"],"peopleInVerse":["Paul","Jesus"]},"2":{"text":"Grace be unto you, and peace, from God our Father, and from the Lord Jesus Christ.","ref":"Philippians 1:2","synthesized":"Grace and peace to you from God our Father and the Lord Jesus Christ.","sources":{"KJV":{"text":"Grace be unto you, and peace, from God our Father, and from the Lord Jesus Christ."},"BSB":{"text":"Grace and peace to you from God our Father and the Lord Jesus Christ."}},"definableWords":["grace","peace","God","Father","Lord","Christ"],"peopleInVerse":["Jesus"]},"3":{"text":"I thank my God upon every remembrance of you,","ref":"Philippians 1:3","synthesized":"I thank my God every time I remember you.","sources":{"KJV":{"text":"I thank my God upon every remembrance of you,"},"BSB":{"text":"I thank my God every time I remember you."}},"definableWords":["God","remember"],"peopleInVerse":[]},"4":{"text":"Always in every prayer of mine for you all making request with joy,","ref":"Philippians 1:4","synthesized":"In every prayer for all of you, I always pray with joy,","sources":{"KJV":{"text":"Always in every prayer of mine for you all making request with joy,"},"BSB":{"text":"In every prayer for all of you, I always pray with joy,"}},"definableWords":["prayer","joy"],"peopleInVerse":[]},"5":{"text":"For your fellowship in the gospel from the first day until now;","ref":"Philippians 1:5","synthesized":"because of your partnership in the gospel from the first day until now,","sources":{"KJV":{"text":"For your fellowship in the gospel from the first day until now;"},"BSB":{"text":"because of your partnership in the gospel from the first day until now,"}},"definableWords":["gospel","day"],"peopleInVerse":[]},"6":{"text":"Being confident of this very thing, that he which hath begun a good work in you will perform it until the day of Jesus Christ:","ref":"Philippians 1:6","synthesized":"being confident of this, that He who began a good work in you will carry it on to completion until the day of Christ Jesus.","sources":{"KJV":{"text":"Being confident of this very thing, that he which hath begun a good work in you will perform it until the day of Jesus Christ:"},"BSB":{"text":"being confident of this, that He who began a good work in you will carry it on to completion until the day of Christ Jesus."}},"definableWords":["good","work","day","Christ"],"peopleInVerse":["Jesus"]},"7":{"text":"Even as it is meet for me to think this of you all, because I have you in my heart; inasmuch as both in my bonds, and in the defence and confirmation of the gospel, ye all are partakers of my grace.","ref":"Philippians 1:7","synthesized":"It is right for me to feel this way about all of you, since I have you in my heart. For in my chains and in my defense and confirmation of the gospel, you are all partners in grace with me.","sources":{"KJV":{"text":"Even as it is meet for me to think this of you all, because I have you in my heart; inasmuch as both in my bonds, and in the defence and confirmation of the gospel, ye all are partakers of my grace."},"BSB":{"text":"It is right for me to feel this way about all of you, since I have you in my heart. For in my chains and in my defense and confirmation of the gospel, you are all partners in grace with me."}},"definableWords":["way","heart","gospel","grace"],"peopleInVerse":[]},"8":{"text":"For God is my record, how greatly I long after you all in the bowels of Jesus Christ.","ref":"Philippians 1:8","synthesized":"God is my witness how I long for all of you with the affection of Christ Jesus.","sources":{"KJV":{"text":"For God is my record, how greatly I long after you all in the bowels of Jesus Christ."},"BSB":{"text":"God is my witness how I long for all of you with the affection of Christ Jesus."}},"definableWords":["God","Christ"],"peopleInVerse":["Jesus"]},"9":{"text":"And this I pray, that your love may abound yet more and more in knowledge and in all judgment;","ref":"Philippians 1:9","synthesized":"And this is my prayer: that your love may abound more and more in knowledge and depth of insight,","sources":{"KJV":{"text":"And this I pray, that your love may abound yet more and more in knowledge and in all judgment;"},"BSB":{"text":"And this is my prayer: that your love may abound more and more in knowledge and depth of insight,"}},"definableWords":["prayer","love","knowledge"],"peopleInVerse":[]},"10":{"text":"That ye may approve things that are excellent; that ye may be sincere and without offence till the day of Christ;","ref":"Philippians 1:10","synthesized":"so that you may be able to test and prove what is best and may be pure and blameless for the day of Christ,","sources":{"KJV":{"text":"That ye may approve things that are excellent; that ye may be sincere and without offence till the day of Christ;"},"BSB":{"text":"so that you may be able to test and prove what is best and may be pure and blameless for the day of Christ,"}},"definableWords":["day","Christ"],"peopleInVerse":[]},"11":{"text":"Being filled with the fruits of righteousness, which are by Jesus Christ, unto the glory and praise of God.","ref":"Philippians 1:11","synthesized":"filled with the fruit of righteousness that comes through Jesus Christ, to the glory and praise of God.","sources":{"KJV":{"text":"Being filled with the fruits of righteousness, which are by Jesus Christ, unto the glory and praise of God."},"BSB":{"text":"filled with the fruit of righteousness that comes through Jesus Christ, to the glory and praise of God."}},"definableWords":["righteousness","Christ","glory","praise","God"],"peopleInVerse":["Jesus"]},"12":{"text":"But I would ye should understand, brethren, that the things which happened unto me have fallen out rather unto the furtherance of the gospel;","ref":"Philippians 1:12","synthesized":"Now I want you to know, brothers, that my circumstances have actually served to advance the gospel.","sources":{"KJV":{"text":"But I would ye should understand, brethren, that the things which happened unto me have fallen out rather unto the furtherance of the gospel;"},"BSB":{"text":"Now I want you to know, brothers, that my circumstances have actually served to advance the gospel."}},"definableWords":["gospel"],"peopleInVerse":[]},"13":{"text":"So that my bonds in Christ are manifest in all the palace, and in all other places;","ref":"Philippians 1:13","synthesized":"As a result, it has become clear throughout the whole palace guard and to everyone else that I am in chains for Christ.","sources":{"KJV":{"text":"So that my bonds in Christ are manifest in all the palace, and in all other places;"},"BSB":{"text":"As a result, it has become clear throughout the whole palace guard and to everyone else that I am in chains for Christ."}},"definableWords":["Christ"],"peopleInVerse":[]},"14":{"text":"And many of the brethren in the Lord, waxing confident by my bonds, are much more bold to speak the word without fear.","ref":"Philippians 1:14","synthesized":"And most of the brothers, confident in the Lord by my chains, now dare more greatly to speak the word without fear.","sources":{"KJV":{"text":"And many of the brethren in the Lord, waxing confident by my bonds, are much more bold to speak the word without fear."},"BSB":{"text":"And most of the brothers, confident in the Lord by my chains, now dare more greatly to speak the word without fear."}},"definableWords":["Lord","word","fear"],"peopleInVerse":[]},"15":{"text":"Some indeed preach Christ even of envy and strife; and some also of good will:","ref":"Philippians 1:15","synthesized":"It is true that some preach Christ out of envy and rivalry, but others out of goodwill.","sources":{"KJV":{"text":"Some indeed preach Christ even of envy and strife; and some also of good will:"},"BSB":{"text":"It is true that some preach Christ out of envy and rivalry, but others out of goodwill."}},"definableWords":["Christ"],"peopleInVerse":[]},"16":{"text":"The one preach Christ of contention, not sincerely, supposing to add affliction to my bonds:","ref":"Philippians 1:16","synthesized":"The latter do so in love, knowing that I am appointed for the defense of the gospel.","sources":{"KJV":{"text":"The one preach Christ of contention, not sincerely, supposing to add affliction to my bonds:"},"BSB":{"text":"The latter do so in love, knowing that I am appointed for the defense of the gospel."}},"definableWords":["love","gospel"],"peopleInVerse":[]},"17":{"text":"But the other of love, knowing that I am set for the defence of the gospel.","ref":"Philippians 1:17","synthesized":"The former, however, preach Christ out of selfish ambition, not sincerely, supposing that they can add to the distress of my chains.","sources":{"KJV":{"text":"But the other of love, knowing that I am set for the defence of the gospel."},"BSB":{"text":"The former, however, preach Christ out of selfish ambition, not sincerely, supposing that they can add to the distress of my chains."}},"definableWords":["Christ"],"peopleInVerse":[]},"18":{"text":"What then? notwithstanding, every way, whether in pretence, or in truth, Christ is preached; and I therein do rejoice, yea, and will rejoice.","ref":"Philippians 1:18","synthesized":"What then is the issue? Just this: that in every way, whether by false motives or true, Christ is preached. And in this I rejoice. Yes, and I will continue to rejoice,","sources":{"KJV":{"text":"What then? notwithstanding, every way, whether in pretence, or in truth, Christ is preached; and I therein do rejoice, yea, and will rejoice."},"BSB":{"text":"What then is the issue? Just this: that in every way, whether by false motives or true, Christ is preached. And in this I rejoice. Yes, and I will continue to rejoice,"}},"definableWords":["way","or","Christ"],"peopleInVerse":[]},"19":{"text":"For I know that this shall turn to my salvation through your prayer, and the supply of the Spirit of Jesus Christ,","ref":"Philippians 1:19","synthesized":"because I know that through your prayers and the provision of the Spirit of Jesus Christ, my distress will turn out for my deliverance.","sources":{"KJV":{"text":"For I know that this shall turn to my salvation through your prayer, and the supply of the Spirit of Jesus Christ,"},"BSB":{"text":"because I know that through your prayers and the provision of the Spirit of Jesus Christ, my distress will turn out for my deliverance."}},"definableWords":["Spirit","Christ"],"peopleInVerse":["Jesus"]},"20":{"text":"According to my earnest expectation and my hope, that in nothing I shall be ashamed, but that with all boldness, as always, so now also Christ shall be magnified in my body, whether it be by life, or by death.","ref":"Philippians 1:20","synthesized":"I eagerly expect and hope that I will in no way be ashamed, but will have complete boldness so that now as always Christ will be exalted in my body, whether by life or by death.","sources":{"KJV":{"text":"According to my earnest expectation and my hope, that in nothing I shall be ashamed, but that with all boldness, as always, so now also Christ shall be magnified in my body, whether it be by life, or by death."},"BSB":{"text":"I eagerly expect and hope that I will in no way be ashamed, but will have complete boldness so that now as always Christ will be exalted in my body, whether by life or by death."}},"definableWords":["hope","way","Christ","life","or","death"],"peopleInVerse":[]},"21":{"text":"For to me to live is Christ, and to die is gain.","ref":"Philippians 1:21","synthesized":"For to me, to live is Christ, and to die is gain.","sources":{"KJV":{"text":"For to me to live is Christ, and to die is gain."},"BSB":{"text":"For to me, to live is Christ, and to die is gain."}},"definableWords":["live","Christ","die"],"peopleInVerse":[]},"22":{"text":"But if I live in the flesh, this is the fruit of my labour: yet what I shall choose I wot not.","ref":"Philippians 1:22","synthesized":"But if I go on living in the body, this will mean fruitful labor for me. So what shall I choose? I do not know.","sources":{"KJV":{"text":"But if I live in the flesh, this is the fruit of my labour: yet what I shall choose I wot not."},"BSB":{"text":"But if I go on living in the body, this will mean fruitful labor for me. So what shall I choose? I do not know."}},"definableWords":["living","fruitful"],"peopleInVerse":[]},"23":{"text":"For I am in a strait betwixt two, having a desire to depart, and to be with Christ; which is far better:","ref":"Philippians 1:23","synthesized":"I am torn between the two. I desire to depart and be with Christ, which is far better indeed.","sources":{"KJV":{"text":"For I am in a strait betwixt two, having a desire to depart, and to be with Christ; which is far better:"},"BSB":{"text":"I am torn between the two. I desire to depart and be with Christ, which is far better indeed."}},"definableWords":["Christ"],"peopleInVerse":[]},"24":{"text":"Nevertheless to abide in the flesh is more needful for you.","ref":"Philippians 1:24","synthesized":"But it is more necessary for you that I remain in the body.","sources":{"KJV":{"text":"Nevertheless to abide in the flesh is more needful for you."},"BSB":{"text":"But it is more necessary for you that I remain in the body."}},"definableWords":[],"peopleInVerse":[]},"25":{"text":"And having this confidence, I know that I shall abide and continue with you all for your furtherance and joy of faith;","ref":"Philippians 1:25","synthesized":"Convinced of this, I know that I will remain and will continue with all of you for your progress and joy in the faith,","sources":{"KJV":{"text":"And having this confidence, I know that I shall abide and continue with you all for your furtherance and joy of faith;"},"BSB":{"text":"Convinced of this, I know that I will remain and will continue with all of you for your progress and joy in the faith,"}},"definableWords":["joy","faith"],"peopleInVerse":[]},"26":{"text":"That your rejoicing may be more abundant in Jesus Christ for me by my coming to you again.","ref":"Philippians 1:26","synthesized":"so that through my coming to you again your exultation in Christ Jesus will resound on account of me.","sources":{"KJV":{"text":"That your rejoicing may be more abundant in Jesus Christ for me by my coming to you again."},"BSB":{"text":"so that through my coming to you again your exultation in Christ Jesus will resound on account of me."}},"definableWords":["Christ"],"peopleInVerse":["Jesus"]},"27":{"text":"Only let your conversation be as it becometh the gospel of Christ: that whether I come and see you, or else be absent, I may hear of your affairs, that ye stand fast in one spirit, with one mind striving together for the faith of the gospel;","ref":"Philippians 1:27","synthesized":"Nevertheless, conduct yourselves in a manner worthy of the gospel of Christ. Then, whether I come and see you or only hear about you in my absence, I will know that you stand firm in one spirit, contending side by side for the faith of the gospel,","sources":{"KJV":{"text":"Only let your conversation be as it becometh the gospel of Christ: that whether I come and see you, or else be absent, I may hear of your affairs, that ye stand fast in one spirit, with one mind striving together for the faith of the gospel;"},"BSB":{"text":"Nevertheless, conduct yourselves in a manner worthy of the gospel of Christ. Then, whether I come and see you or only hear about you in my absence, I will know that you stand firm in one spirit, contending side by side for the faith of the gospel,"}},"definableWords":["gospel","Christ","see","or","hear","stand","one","spirit","faith"],"peopleInVerse":[]},"28":{"text":"And in nothing terrified by your adversaries: which is to them an evident token of perdition, but to you of salvation, and that of God.","ref":"Philippians 1:28","synthesized":"without being frightened in any way by those who oppose you. This is a clear sign of their destruction but of your salvation, and it is from God.","sources":{"KJV":{"text":"And in nothing terrified by your adversaries: which is to them an evident token of perdition, but to you of salvation, and that of God."},"BSB":{"text":"without being frightened in any way by those who oppose you. This is a clear sign of their destruction but of your salvation, and it is from God."}},"definableWords":["way","salvation","God"],"peopleInVerse":[]},"29":{"text":"For unto you it is given in the behalf of Christ, not only to believe on him, but also to suffer for his sake;","ref":"Philippians 1:29","synthesized":"For it has been granted to you on behalf of Christ not only to believe in Him, but also to suffer for Him,","sources":{"KJV":{"text":"For unto you it is given in the behalf of Christ, not only to believe on him, but also to suffer for his sake;"},"BSB":{"text":"For it has been granted to you on behalf of Christ not only to believe in Him, but also to suffer for Him,"}},"definableWords":["Christ"],"peopleInVerse":[]},"30":{"text":"Having the same conflict which ye saw in me, and now hear to be in me.","ref":"Philippians 1:30","synthesized":"since you are encountering the same struggle you saw I had, and now hear that I still have.","sources":{"KJV":{"text":"Having the same conflict which ye saw in me, and now hear to be in me."},"BSB":{"text":"since you are encountering the same struggle you saw I had, and now hear that I still have."}},"definableWords":["saw","hear"],"peopleInVerse":[]}}},"2":{"chapter":"2","title":"CHRIST EMPTIED HIMSELF","verses":{"1":{"text":"If there be therefore any consolation in Christ, if any comfort of love, if any fellowship of the Spirit, if any bowels and mercies,","ref":"Philippians 2:1","synthesized":"Therefore if you have any encouragement in Christ, if any comfort from His love, if any fellowship with the Spirit, if any affection and compassion,","sources":{"KJV":{"text":"If there be therefore any consolation in Christ, if any comfort of love, if any fellowship of the Spirit, if any bowels and mercies,"},"BSB":{"text":"Therefore if you have any encouragement in Christ, if any comfort from His love, if any fellowship with the Spirit, if any affection and compassion,"}},"definableWords":["Christ","love","Spirit"],"peopleInVerse":[]},"2":{"text":"Fulfil ye my joy, that ye be likeminded, having the same love, being of one accord, of one mind.","ref":"Philippians 2:2","synthesized":"then make my joy complete by being like-minded, having the same love, being united in spirit and purpose.","sources":{"KJV":{"text":"Fulfil ye my joy, that ye be likeminded, having the same love, being of one accord, of one mind."},"BSB":{"text":"then make my joy complete by being like-minded, having the same love, being united in spirit and purpose."}},"definableWords":["make","joy","love","spirit"],"peopleInVerse":[]},"3":{"text":"Let nothing be done through strife or vainglory; but in lowliness of mind let each esteem other better than themselves.","ref":"Philippians 2:3","synthesized":"Do nothing out of selfish ambition or empty pride, but in humility consider others more important than yourselves.","sources":{"KJV":{"text":"Let nothing be done through strife or vainglory; but in lowliness of mind let each esteem other better than themselves."},"BSB":{"text":"Do nothing out of selfish ambition or empty pride, but in humility consider others more important than yourselves."}},"definableWords":["or"],"peopleInVerse":[]},"4":{"text":"Look not every man on his own things, but every man also on the things of others.","ref":"Philippians 2:4","synthesized":"Each of you should look not only to your own interests, but also to the interests of others.","sources":{"KJV":{"text":"Look not every man on his own things, but every man also on the things of others."},"BSB":{"text":"Each of you should look not only to your own interests, but also to the interests of others."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"Let this mind be in you, which was also in Christ Jesus:","ref":"Philippians 2:5","synthesized":"Let this mind be in you which was also in Christ Jesus:","sources":{"KJV":{"text":"Let this mind be in you, which was also in Christ Jesus:"},"BSB":{"text":"Let this mind be in you which was also in Christ Jesus:"}},"definableWords":["mind","Christ"],"peopleInVerse":["Jesus"]},"6":{"text":"Who, being in the form of God, thought it not robbery to be equal with God:","ref":"Philippians 2:6","synthesized":"Who, existing in the form of God, did not consider equality with God something to be grasped,","sources":{"KJV":{"text":"Who, being in the form of God, thought it not robbery to be equal with God:"},"BSB":{"text":"Who, existing in the form of God, did not consider equality with God something to be grasped,"}},"definableWords":["form","God"],"peopleInVerse":[]},"7":{"text":"But made himself of no reputation, and took upon him the form of a servant, and was made in the likeness of men:","ref":"Philippians 2:7","synthesized":"but emptied Himself, taking the form of a servant, being made in human likeness.","sources":{"KJV":{"text":"But made himself of no reputation, and took upon him the form of a servant, and was made in the likeness of men:"},"BSB":{"text":"but emptied Himself, taking the form of a servant, being made in human likeness."}},"definableWords":["form","servant","made","likeness"],"peopleInVerse":[]},"8":{"text":"And being found in fashion as a man, he humbled himself, and became obedient unto death, even the death of the cross.","ref":"Philippians 2:8","synthesized":"And being found in appearance as a man, He humbled Himself and became obedient to death— even death on a cross.","sources":{"KJV":{"text":"And being found in fashion as a man, he humbled himself, and became obedient unto death, even the death of the cross."},"BSB":{"text":"And being found in appearance as a man, He humbled Himself and became obedient to death— even death on a cross."}},"definableWords":["man","death"],"peopleInVerse":[]},"9":{"text":"Wherefore God also hath highly exalted him, and given him a name which is above every name:","ref":"Philippians 2:9","synthesized":"Therefore God exalted Him to the highest place and gave Him the name above all names,","sources":{"KJV":{"text":"Wherefore God also hath highly exalted him, and given him a name which is above every name:"},"BSB":{"text":"Therefore God exalted Him to the highest place and gave Him the name above all names,"}},"definableWords":["God","name"],"peopleInVerse":[]},"10":{"text":"That at the name of Jesus every knee should bow, of things in heaven, and things in earth, and things under the earth;","ref":"Philippians 2:10","synthesized":"that at the name of Jesus every knee should bow, in heaven and on earth and under the earth,","sources":{"KJV":{"text":"That at the name of Jesus every knee should bow, of things in heaven, and things in earth, and things under the earth;"},"BSB":{"text":"that at the name of Jesus every knee should bow, in heaven and on earth and under the earth,"}},"definableWords":["name","heaven","earth"],"peopleInVerse":["Jesus"]},"11":{"text":"And that every tongue should confess that Jesus Christ is Lord, to the glory of God the Father.","ref":"Philippians 2:11","synthesized":"and every tongue confess that Jesus Christ is Lord, to the glory of God the Father.","sources":{"KJV":{"text":"And that every tongue should confess that Jesus Christ is Lord, to the glory of God the Father."},"BSB":{"text":"and every tongue confess that Jesus Christ is Lord, to the glory of God the Father."}},"definableWords":["Christ","Lord","glory","God","Father"],"peopleInVerse":["Jesus"]},"12":{"text":"Wherefore, my beloved, as ye have always obeyed, not as in my presence only, but now much more in my absence, work out your own salvation with fear and trembling.","ref":"Philippians 2:12","synthesized":"Therefore, my beloved, just as you have always obeyed, not only in my presence, but now even more in my absence, continue to work out your salvation with fear and trembling.","sources":{"KJV":{"text":"Wherefore, my beloved, as ye have always obeyed, not as in my presence only, but now much more in my absence, work out your own salvation with fear and trembling."},"BSB":{"text":"Therefore, my beloved, just as you have always obeyed, not only in my presence, but now even more in my absence, continue to work out your salvation with fear and trembling."}},"definableWords":["work","salvation","fear"],"peopleInVerse":[]},"13":{"text":"For it is God which worketh in you both to will and to do of his good pleasure.","ref":"Philippians 2:13","synthesized":"For it is God who works in you to will and to act on behalf of His good purpose.","sources":{"KJV":{"text":"For it is God which worketh in you both to will and to do of his good pleasure."},"BSB":{"text":"For it is God who works in you to will and to act on behalf of His good purpose."}},"definableWords":["God","works","good"],"peopleInVerse":[]},"14":{"text":"Do all things without murmurings and disputings:","ref":"Philippians 2:14","synthesized":"Do everything without complaining or arguing,","sources":{"KJV":{"text":"Do all things without murmurings and disputings:"},"BSB":{"text":"Do everything without complaining or arguing,"}},"definableWords":["or"],"peopleInVerse":[]},"15":{"text":"That ye may be blameless and harmless, the sons of God, without rebuke, in the midst of a crooked and perverse nation, among whom ye shine as lights in the world;","ref":"Philippians 2:15","synthesized":"so that you may be blameless and pure, children of God without fault in a crooked and perverse generation, in which you shine as lights in the world","sources":{"KJV":{"text":"That ye may be blameless and harmless, the sons of God, without rebuke, in the midst of a crooked and perverse nation, among whom ye shine as lights in the world;"},"BSB":{"text":"so that you may be blameless and pure, children of God without fault in a crooked and perverse generation, in which you shine as lights in the world"}},"definableWords":["God"],"peopleInVerse":[]},"16":{"text":"Holding forth the word of life; that I may rejoice in the day of Christ, that I have not run in vain, neither laboured in vain.","ref":"Philippians 2:16","synthesized":"as you hold forth the word of life, in order that I may boast on the day of Christ that I did not run or labor in vain.","sources":{"KJV":{"text":"Holding forth the word of life; that I may rejoice in the day of Christ, that I have not run in vain, neither laboured in vain."},"BSB":{"text":"as you hold forth the word of life, in order that I may boast on the day of Christ that I did not run or labor in vain."}},"definableWords":["word","life","day","Christ","run","or"],"peopleInVerse":[]},"17":{"text":"Yea, and if I be offered upon the sacrifice and service of your faith, I joy, and rejoice with you all.","ref":"Philippians 2:17","synthesized":"But even if I am being poured out like a drink offering on the sacrifice and service of your faith, I am glad and rejoice with all of you.","sources":{"KJV":{"text":"Yea, and if I be offered upon the sacrifice and service of your faith, I joy, and rejoice with you all."},"BSB":{"text":"But even if I am being poured out like a drink offering on the sacrifice and service of your faith, I am glad and rejoice with all of you."}},"definableWords":["offering","sacrifice","faith"],"peopleInVerse":[]},"18":{"text":"For the same cause also do ye joy, and rejoice with me.","ref":"Philippians 2:18","synthesized":"So you too should be glad and rejoice with me.","sources":{"KJV":{"text":"For the same cause also do ye joy, and rejoice with me."},"BSB":{"text":"So you too should be glad and rejoice with me."}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"But I trust in the Lord Jesus to send Timotheus shortly unto you, that I also may be of good comfort, when I know your state.","ref":"Philippians 2:19","synthesized":"Now I hope in the Lord Jesus to send Timothy to you soon, that I also may be cheered when I learn how you are doing.","sources":{"KJV":{"text":"But I trust in the Lord Jesus to send Timotheus shortly unto you, that I also may be of good comfort, when I know your state."},"BSB":{"text":"Now I hope in the Lord Jesus to send Timothy to you soon, that I also may be cheered when I learn how you are doing."}},"definableWords":["hope","Lord"],"peopleInVerse":["Jesus"]},"20":{"text":"For I have no man likeminded, who will naturally care for your state.","ref":"Philippians 2:20","synthesized":"I have nobody else like him who will genuinely care for your needs.","sources":{"KJV":{"text":"For I have no man likeminded, who will naturally care for your state."},"BSB":{"text":"I have nobody else like him who will genuinely care for your needs."}},"definableWords":[],"peopleInVerse":[]},"21":{"text":"For all seek their own, not the things which are Jesus Christ’s.","ref":"Philippians 2:21","synthesized":"For all the others look after their own interests, not those of Jesus Christ.","sources":{"KJV":{"text":"For all seek their own, not the things which are Jesus Christ’s."},"BSB":{"text":"For all the others look after their own interests, not those of Jesus Christ."}},"definableWords":["Christ"],"peopleInVerse":["Jesus"]},"22":{"text":"But ye know the proof of him, that, as a son with the father, he hath served with me in the gospel.","ref":"Philippians 2:22","synthesized":"But you know Timothy’s proven worth, that as a child with his father he has served with me to advance the gospel.","sources":{"KJV":{"text":"But ye know the proof of him, that, as a son with the father, he hath served with me in the gospel."},"BSB":{"text":"But you know Timothy’s proven worth, that as a child with his father he has served with me to advance the gospel."}},"definableWords":["father","gospel"],"peopleInVerse":[]},"23":{"text":"Him therefore I hope to send presently, so soon as I shall see how it will go with me.","ref":"Philippians 2:23","synthesized":"So I hope to send him as soon as I see what happens with me.","sources":{"KJV":{"text":"Him therefore I hope to send presently, so soon as I shall see how it will go with me."},"BSB":{"text":"So I hope to send him as soon as I see what happens with me."}},"definableWords":["hope","see"],"peopleInVerse":[]},"24":{"text":"But I trust in the Lord that I also myself shall come shortly.","ref":"Philippians 2:24","synthesized":"And I trust in the Lord that I myself will come soon.","sources":{"KJV":{"text":"But I trust in the Lord that I also myself shall come shortly."},"BSB":{"text":"And I trust in the Lord that I myself will come soon."}},"definableWords":["trust","Lord"],"peopleInVerse":[]},"25":{"text":"Yet I supposed it necessary to send to you Epaphroditus, my brother, and companion in labour, and fellowsoldier, but your messenger, and he that ministered to my wants.","ref":"Philippians 2:25","synthesized":"But I thought it necessary to send back to you Epaphroditus, my brother, fellow worker, and fellow soldier, who is also your messenger and minister to my needs.","sources":{"KJV":{"text":"Yet I supposed it necessary to send to you Epaphroditus, my brother, and companion in labour, and fellowsoldier, but your messenger, and he that ministered to my wants."},"BSB":{"text":"But I thought it necessary to send back to you Epaphroditus, my brother, fellow worker, and fellow soldier, who is also your messenger and minister to my needs."}},"definableWords":["brother"],"peopleInVerse":[]},"26":{"text":"For he longed after you all, and was full of heaviness, because that ye had heard that he had been sick.","ref":"Philippians 2:26","synthesized":"For he has been longing for all of you and is distressed because you heard he was ill.","sources":{"KJV":{"text":"For he longed after you all, and was full of heaviness, because that ye had heard that he had been sick."},"BSB":{"text":"For he has been longing for all of you and is distressed because you heard he was ill."}},"definableWords":[],"peopleInVerse":[]},"27":{"text":"For indeed he was sick nigh unto death: but God had mercy on him; and not on him only, but on me also, lest I should have sorrow upon sorrow.","ref":"Philippians 2:27","synthesized":"He was sick indeed, nearly unto death. But God had mercy on him, and not only on him but also on me, to spare me sorrow upon sorrow.","sources":{"KJV":{"text":"For indeed he was sick nigh unto death: but God had mercy on him; and not on him only, but on me also, lest I should have sorrow upon sorrow."},"BSB":{"text":"He was sick indeed, nearly unto death. But God had mercy on him, and not only on him but also on me, to spare me sorrow upon sorrow."}},"definableWords":["death","God","mercy"],"peopleInVerse":[]},"28":{"text":"I sent him therefore the more carefully, that, when ye see him again, ye may rejoice, and that I may be the less sorrowful.","ref":"Philippians 2:28","synthesized":"Therefore I am all the more eager to send him, so that when you see him again you may rejoice, and I may be less anxious.","sources":{"KJV":{"text":"I sent him therefore the more carefully, that, when ye see him again, ye may rejoice, and that I may be the less sorrowful."},"BSB":{"text":"Therefore I am all the more eager to send him, so that when you see him again you may rejoice, and I may be less anxious."}},"definableWords":["see"],"peopleInVerse":[]},"29":{"text":"Receive him therefore in the Lord with all gladness; and hold such in reputation:","ref":"Philippians 2:29","synthesized":"Welcome him in the Lord with great joy, and honor men like him,","sources":{"KJV":{"text":"Receive him therefore in the Lord with all gladness; and hold such in reputation:"},"BSB":{"text":"Welcome him in the Lord with great joy, and honor men like him,"}},"definableWords":["Lord","great","joy","men"],"peopleInVerse":[]},"30":{"text":"Because for the work of Christ he was nigh unto death, not regarding his life, to supply your lack of service toward me.","ref":"Philippians 2:30","synthesized":"because he nearly died for the work of Christ, risking his life to make up for your deficit of service to me.","sources":{"KJV":{"text":"Because for the work of Christ he was nigh unto death, not regarding his life, to supply your lack of service toward me."},"BSB":{"text":"because he nearly died for the work of Christ, risking his life to make up for your deficit of service to me."}},"definableWords":["work","Christ","life","make"],"peopleInVerse":[]}}},"3":{"chapter":"3","title":"I PRESS TOWARD THE MARK","verses":{"1":{"text":"Finally, my brethren, rejoice in the Lord. To write the same things to you, to me indeed is not grievous, but for you it is safe.","ref":"Philippians 3:1","synthesized":"Finally, my brothers, rejoice in the Lord. It is no trouble for me to write the same things to you again, and it is a safeguard for you.","sources":{"KJV":{"text":"Finally, my brethren, rejoice in the Lord. To write the same things to you, to me indeed is not grievous, but for you it is safe."},"BSB":{"text":"Finally, my brothers, rejoice in the Lord. It is no trouble for me to write the same things to you again, and it is a safeguard for you."}},"definableWords":["Lord"],"peopleInVerse":[]},"2":{"text":"Beware of dogs, beware of evil workers, beware of the concision.","ref":"Philippians 3:2","synthesized":"Watch out for those dogs, those workers of evil, those mutilators of the flesh!","sources":{"KJV":{"text":"Beware of dogs, beware of evil workers, beware of the concision."},"BSB":{"text":"Watch out for those dogs, those workers of evil, those mutilators of the flesh!"}},"definableWords":["evil","flesh"],"peopleInVerse":[]},"3":{"text":"For we are the circumcision, which worship God in the spirit, and rejoice in Christ Jesus, and have no confidence in the flesh.","ref":"Philippians 3:3","synthesized":"For it is we who are the circumcision, we who worship by the Spirit of God, who glory in Christ Jesus, and who put no confidence in the flesh—","sources":{"KJV":{"text":"For we are the circumcision, which worship God in the spirit, and rejoice in Christ Jesus, and have no confidence in the flesh."},"BSB":{"text":"For it is we who are the circumcision, we who worship by the Spirit of God, who glory in Christ Jesus, and who put no confidence in the flesh—"}},"definableWords":["circumcision","worship","Spirit","God","glory","Christ","flesh"],"peopleInVerse":["Jesus"]},"4":{"text":"Though I might also have confidence in the flesh. If any other man thinketh that he hath whereof he might trust in the flesh, I more:","ref":"Philippians 3:4","synthesized":"though I myself could have such confidence.  If anyone else thinks he has grounds for confidence in the flesh, I have more:","sources":{"KJV":{"text":"Though I might also have confidence in the flesh. If any other man thinketh that he hath whereof he might trust in the flesh, I more:"},"BSB":{"text":"though I myself could have such confidence.  If anyone else thinks he has grounds for confidence in the flesh, I have more:"}},"definableWords":["flesh"],"peopleInVerse":[]},"5":{"text":"Circumcised the eighth day, of the stock of Israel, of the tribe of Benjamin, an Hebrew of the Hebrews; as touching the law, a Pharisee;","ref":"Philippians 3:5","synthesized":"circumcised on the eighth day, of the people of Israel, of the tribe of Benjamin; a Hebrew of Hebrews; as to the law, a Pharisee;","sources":{"KJV":{"text":"Circumcised the eighth day, of the stock of Israel, of the tribe of Benjamin, an Hebrew of the Hebrews; as touching the law, a Pharisee;"},"BSB":{"text":"circumcised on the eighth day, of the people of Israel, of the tribe of Benjamin; a Hebrew of Hebrews; as to the law, a Pharisee;"}},"definableWords":["circumcised","day","people","Israel","tribe","Benjamin","law","Pharisee"],"peopleInVerse":[]},"6":{"text":"Concerning zeal, persecuting the church; touching the righteousness which is in the law, blameless.","ref":"Philippians 3:6","synthesized":"as to zeal, persecuting the church; as to righteousness in the law, faultless.","sources":{"KJV":{"text":"Concerning zeal, persecuting the church; touching the righteousness which is in the law, blameless."},"BSB":{"text":"as to zeal, persecuting the church; as to righteousness in the law, faultless."}},"definableWords":["church","righteousness","law"],"peopleInVerse":[]},"7":{"text":"But what things were gain to me, those I counted loss for Christ.","ref":"Philippians 3:7","synthesized":"But whatever was gain to me I count as loss for the sake of Christ.","sources":{"KJV":{"text":"But what things were gain to me, those I counted loss for Christ."},"BSB":{"text":"But whatever was gain to me I count as loss for the sake of Christ."}},"definableWords":["Christ"],"peopleInVerse":[]},"8":{"text":"Yea doubtless, and I count all things but loss for the excellency of the knowledge of Christ Jesus my Lord: for whom I have suffered the loss of all things, and do count them but dung, that I may win Christ,","ref":"Philippians 3:8","synthesized":"More than that, I count all things as loss compared to the surpassing excellence of knowing Christ Jesus my Lord, for whom I have lost all things. I consider them rubbish, that I may gain Christ","sources":{"KJV":{"text":"Yea doubtless, and I count all things but loss for the excellency of the knowledge of Christ Jesus my Lord: for whom I have suffered the loss of all things, and do count them but dung, that I may win Christ,"},"BSB":{"text":"More than that, I count all things as loss compared to the surpassing excellence of knowing Christ Jesus my Lord, for whom I have lost all things. I consider them rubbish, that I may gain Christ"}},"definableWords":["Christ","Lord"],"peopleInVerse":["Jesus"]},"9":{"text":"And be found in him, not having mine own righteousness, which is of the law, but that which is through the faith of Christ, the righteousness which is of God by faith:","ref":"Philippians 3:9","synthesized":"and be found in Him, not having my own righteousness from the law, but that which is through faith in Christ, the righteousness from God on the basis of faith.","sources":{"KJV":{"text":"And be found in him, not having mine own righteousness, which is of the law, but that which is through the faith of Christ, the righteousness which is of God by faith:"},"BSB":{"text":"and be found in Him, not having my own righteousness from the law, but that which is through faith in Christ, the righteousness from God on the basis of faith."}},"definableWords":["righteousness","law","faith","Christ","God"],"peopleInVerse":[]},"10":{"text":"That I may know him, and the power of his resurrection, and the fellowship of his sufferings, being made conformable unto his death;","ref":"Philippians 3:10","synthesized":"I want to know Christ and the power of His resurrection and the fellowship of His sufferings, being conformed to Him in His death,","sources":{"KJV":{"text":"That I may know him, and the power of his resurrection, and the fellowship of his sufferings, being made conformable unto his death;"},"BSB":{"text":"I want to know Christ and the power of His resurrection and the fellowship of His sufferings, being conformed to Him in His death,"}},"definableWords":["Christ","resurrection","death"],"peopleInVerse":[]},"11":{"text":"If by any means I might attain unto the resurrection of the dead.","ref":"Philippians 3:11","synthesized":"and so, somehow, to attain to the resurrection from the dead.","sources":{"KJV":{"text":"If by any means I might attain unto the resurrection of the dead."},"BSB":{"text":"and so, somehow, to attain to the resurrection from the dead."}},"definableWords":["resurrection"],"peopleInVerse":[]},"12":{"text":"Not as though I had already attained, either were already perfect: but I follow after, if that I may apprehend that for which also I am apprehended of Christ Jesus.","ref":"Philippians 3:12","synthesized":"Not that I have already obtained all this, or have already been made perfect, but I press on to take hold of that for which Christ Jesus took hold of me.","sources":{"KJV":{"text":"Not as though I had already attained, either were already perfect: but I follow after, if that I may apprehend that for which also I am apprehended of Christ Jesus."},"BSB":{"text":"Not that I have already obtained all this, or have already been made perfect, but I press on to take hold of that for which Christ Jesus took hold of me."}},"definableWords":["or","made","Christ"],"peopleInVerse":["Jesus"]},"13":{"text":"Brethren, I count not myself to have apprehended: but this one thing I do, forgetting those things which are behind, and reaching forth unto those things which are before,","ref":"Philippians 3:13","synthesized":"Brothers, I do not consider myself yet to have taken hold of it. But one thing I do: Forgetting what is behind and straining toward what is ahead,","sources":{"KJV":{"text":"Brethren, I count not myself to have apprehended: but this one thing I do, forgetting those things which are behind, and reaching forth unto those things which are before,"},"BSB":{"text":"Brothers, I do not consider myself yet to have taken hold of it. But one thing I do: Forgetting what is behind and straining toward what is ahead,"}},"definableWords":["one"],"peopleInVerse":[]},"14":{"text":"I press toward the mark for the prize of the high calling of God in Christ Jesus.","ref":"Philippians 3:14","synthesized":"I press on toward the goal to win the prize of God’s heavenly calling in Christ Jesus.","sources":{"KJV":{"text":"I press toward the mark for the prize of the high calling of God in Christ Jesus."},"BSB":{"text":"I press on toward the goal to win the prize of God’s heavenly calling in Christ Jesus."}},"definableWords":["God","Christ"],"peopleInVerse":["Jesus"]},"15":{"text":"Let us therefore, as many as be perfect, be thus minded: and if in any thing ye be otherwise minded, God shall reveal even this unto you.","ref":"Philippians 3:15","synthesized":"All of us who are mature should embrace this point of view. And if you think differently about some issue, God will reveal this to you as well.","sources":{"KJV":{"text":"Let us therefore, as many as be perfect, be thus minded: and if in any thing ye be otherwise minded, God shall reveal even this unto you."},"BSB":{"text":"All of us who are mature should embrace this point of view. And if you think differently about some issue, God will reveal this to you as well."}},"definableWords":["God"],"peopleInVerse":[]},"16":{"text":"Nevertheless, whereto we have already attained, let us walk by the same rule, let us mind the same thing.","ref":"Philippians 3:16","synthesized":"Nevertheless, we must live up to what we have already attained.","sources":{"KJV":{"text":"Nevertheless, whereto we have already attained, let us walk by the same rule, let us mind the same thing."},"BSB":{"text":"Nevertheless, we must live up to what we have already attained."}},"definableWords":["live"],"peopleInVerse":[]},"17":{"text":"Brethren, be followers together of me, and mark them which walk so as ye have us for an ensample.","ref":"Philippians 3:17","synthesized":"Join one another in following my example, brothers, and carefully observe those who walk according to the pattern we set for you.","sources":{"KJV":{"text":"Brethren, be followers together of me, and mark them which walk so as ye have us for an ensample."},"BSB":{"text":"Join one another in following my example, brothers, and carefully observe those who walk according to the pattern we set for you."}},"definableWords":["one","walk"],"peopleInVerse":[]},"18":{"text":"(For many walk, of whom I have told you often, and now tell you even weeping, that they are the enemies of the cross of Christ:","ref":"Philippians 3:18","synthesized":"For as I have often told you before, and now say again even with tears: Many live as enemies of the cross of Christ.","sources":{"KJV":{"text":"(For many walk, of whom I have told you often, and now tell you even weeping, that they are the enemies of the cross of Christ:"},"BSB":{"text":"For as I have often told you before, and now say again even with tears: Many live as enemies of the cross of Christ."}},"definableWords":["live","Christ"],"peopleInVerse":[]},"19":{"text":"Whose end is destruction, whose God is their belly, and whose glory is in their shame, who mind earthly things.)","ref":"Philippians 3:19","synthesized":"Their end is destruction, their god is their belly, and their glory is in their shame. Their minds are set on earthly things.","sources":{"KJV":{"text":"Whose end is destruction, whose God is their belly, and whose glory is in their shame, who mind earthly things.)"},"BSB":{"text":"Their end is destruction, their god is their belly, and their glory is in their shame. Their minds are set on earthly things."}},"definableWords":["God","glory"],"peopleInVerse":[]},"20":{"text":"For our conversation is in heaven; from whence also we look for the Saviour, the Lord Jesus Christ:","ref":"Philippians 3:20","synthesized":"But our citizenship is in heaven, and we eagerly await a Savior from there, the Lord Jesus Christ,","sources":{"KJV":{"text":"For our conversation is in heaven; from whence also we look for the Saviour, the Lord Jesus Christ:"},"BSB":{"text":"But our citizenship is in heaven, and we eagerly await a Savior from there, the Lord Jesus Christ,"}},"definableWords":["heaven","Lord","Christ"],"peopleInVerse":["Jesus"]},"21":{"text":"Who shall change our vile body, that it may be fashioned like unto his glorious body, according to the working whereby he is able even to subdue all things unto himself.","ref":"Philippians 3:21","synthesized":"who, by the power that enables Him to subject all things to Himself, will transform our lowly bodies to be like His glorious body.","sources":{"KJV":{"text":"Who shall change our vile body, that it may be fashioned like unto his glorious body, according to the working whereby he is able even to subdue all things unto himself."},"BSB":{"text":"who, by the power that enables Him to subject all things to Himself, will transform our lowly bodies to be like His glorious body."}},"definableWords":[],"peopleInVerse":[]}}},"4":{"chapter":"4","title":"REJOICE IN THE LORD ALWAY","verses":{"1":{"text":"Therefore, my brethren dearly beloved and longed for, my joy and crown, so stand fast in the Lord, my dearly beloved.","ref":"Philippians 4:1","synthesized":"Therefore, my brothers, whom I love and long for, my joy and crown, that is how you must stand firm in the Lord, my beloved.","sources":{"KJV":{"text":"Therefore, my brethren dearly beloved and longed for, my joy and crown, so stand fast in the Lord, my dearly beloved."},"BSB":{"text":"Therefore, my brothers, whom I love and long for, my joy and crown, that is how you must stand firm in the Lord, my beloved."}},"definableWords":["love","joy","crown","stand","Lord"],"peopleInVerse":[]},"2":{"text":"I beseech Euodias, and beseech Syntyche, that they be of the same mind in the Lord.","ref":"Philippians 4:2","synthesized":"I urge Euodia and Syntyche to agree with each other in the Lord.","sources":{"KJV":{"text":"I beseech Euodias, and beseech Syntyche, that they be of the same mind in the Lord."},"BSB":{"text":"I urge Euodia and Syntyche to agree with each other in the Lord."}},"definableWords":["Lord"],"peopleInVerse":[]},"3":{"text":"And I intreat thee also, true yokefellow, help those women which laboured with me in the gospel, with Clement also, and with other my fellowlabourers, whose names are in the book of life.","ref":"Philippians 4:3","synthesized":"Yes, and I ask you, my true yokefellow, to help these women who have labored with me for the gospel, along with Clement and the rest of my fellow workers, whose names are in the Book of Life.","sources":{"KJV":{"text":"And I intreat thee also, true yokefellow, help those women which laboured with me in the gospel, with Clement also, and with other my fellowlabourers, whose names are in the book of life."},"BSB":{"text":"Yes, and I ask you, my true yokefellow, to help these women who have labored with me for the gospel, along with Clement and the rest of my fellow workers, whose names are in the Book of Life."}},"definableWords":["women","gospel","rest","life"],"peopleInVerse":[]},"4":{"text":"Rejoice in the Lord alway: and again I say, Rejoice.","ref":"Philippians 4:4","synthesized":"Rejoice in the Lord always. I will say it again: Rejoice!","sources":{"KJV":{"text":"Rejoice in the Lord alway: and again I say, Rejoice."},"BSB":{"text":"Rejoice in the Lord always. I will say it again: Rejoice!"}},"definableWords":["Lord"],"peopleInVerse":[]},"5":{"text":"Let your moderation be known unto all men. The Lord is at hand.","ref":"Philippians 4:5","synthesized":"Let your gentleness be apparent to all. The Lord is near.","sources":{"KJV":{"text":"Let your moderation be known unto all men. The Lord is at hand."},"BSB":{"text":"Let your gentleness be apparent to all. The Lord is near."}},"definableWords":["Lord"],"peopleInVerse":[]},"6":{"text":"Be careful for nothing; but in every thing by prayer and supplication with thanksgiving let your requests be made known unto God.","ref":"Philippians 4:6","synthesized":"Be anxious for nothing, but in everything, by prayer and petition, with thanksgiving, present your requests to God.","sources":{"KJV":{"text":"Be careful for nothing; but in every thing by prayer and supplication with thanksgiving let your requests be made known unto God."},"BSB":{"text":"Be anxious for nothing, but in everything, by prayer and petition, with thanksgiving, present your requests to God."}},"definableWords":["prayer","God"],"peopleInVerse":[]},"7":{"text":"And the peace of God, which passeth all understanding, shall keep your hearts and minds through Christ Jesus.","ref":"Philippians 4:7","synthesized":"And the peace of God, which surpasses all understanding, will guard your hearts and your minds in Christ Jesus.","sources":{"KJV":{"text":"And the peace of God, which passeth all understanding, shall keep your hearts and minds through Christ Jesus."},"BSB":{"text":"And the peace of God, which surpasses all understanding, will guard your hearts and your minds in Christ Jesus."}},"definableWords":["peace","God","Christ"],"peopleInVerse":["Jesus"]},"8":{"text":"Finally, brethren, whatsoever things are true, whatsoever things are honest, whatsoever things are just, whatsoever things are pure, whatsoever things are lovely, whatsoever things are of good report; if there be any virtue, and if there be any praise, think on these things.","ref":"Philippians 4:8","synthesized":"Finally, brothers, whatever is true, whatever is honorable, whatever is right, whatever is pure, whatever is lovely, whatever is admirable—if anything is excellent or praiseworthy—think on these things.","sources":{"KJV":{"text":"Finally, brethren, whatsoever things are true, whatsoever things are honest, whatsoever things are just, whatsoever things are pure, whatsoever things are lovely, whatsoever things are of good report; if there be any virtue, and if there be any praise, think on these things."},"BSB":{"text":"Finally, brothers, whatever is true, whatever is honorable, whatever is right, whatever is pure, whatever is lovely, whatever is admirable—if anything is excellent or praiseworthy—think on these things."}},"definableWords":["or"],"peopleInVerse":[]},"9":{"text":"Those things, which ye have both learned, and received, and heard, and seen in me, do: and the God of peace shall be with you.","ref":"Philippians 4:9","synthesized":"Whatever you have learned or received or heard from me, or seen in me, put it into practice. And the God of peace will be with you.","sources":{"KJV":{"text":"Those things, which ye have both learned, and received, and heard, and seen in me, do: and the God of peace shall be with you."},"BSB":{"text":"Whatever you have learned or received or heard from me, or seen in me, put it into practice. And the God of peace will be with you."}},"definableWords":["or","God","peace"],"peopleInVerse":[]},"10":{"text":"But I rejoiced in the Lord greatly, that now at the last your care of me hath flourished again; wherein ye were also careful, but ye lacked opportunity.","ref":"Philippians 4:10","synthesized":"Now I rejoice greatly in the Lord that at last you have revived your concern for me. You were indeed concerned, but you had no opportunity to show it.","sources":{"KJV":{"text":"But I rejoiced in the Lord greatly, that now at the last your care of me hath flourished again; wherein ye were also careful, but ye lacked opportunity."},"BSB":{"text":"Now I rejoice greatly in the Lord that at last you have revived your concern for me. You were indeed concerned, but you had no opportunity to show it."}},"definableWords":["Lord"],"peopleInVerse":[]},"11":{"text":"Not that I speak in respect of want: for I have learned, in whatsoever state I am, therewith to be content.","ref":"Philippians 4:11","synthesized":"I am not saying this out of need, for I have learned to be content regardless of my circumstances.","sources":{"KJV":{"text":"Not that I speak in respect of want: for I have learned, in whatsoever state I am, therewith to be content."},"BSB":{"text":"I am not saying this out of need, for I have learned to be content regardless of my circumstances."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"I know both how to be abased, and I know how to abound: every where and in all things I am instructed both to be full and to be hungry, both to abound and to suffer need.","ref":"Philippians 4:12","synthesized":"I know how to live humbly, and I know how to abound. I am accustomed to any and every situation—to being filled and being hungry, to having plenty and having need.","sources":{"KJV":{"text":"I know both how to be abased, and I know how to abound: every where and in all things I am instructed both to be full and to be hungry, both to abound and to suffer need."},"BSB":{"text":"I know how to live humbly, and I know how to abound. I am accustomed to any and every situation—to being filled and being hungry, to having plenty and having need."}},"definableWords":["live"],"peopleInVerse":[]},"13":{"text":"I can do all things through Christ which strengtheneth me.","ref":"Philippians 4:13","synthesized":"I can do all things through Christ who gives me strength.","sources":{"KJV":{"text":"I can do all things through Christ which strengtheneth me."},"BSB":{"text":"I can do all things through Christ who gives me strength."}},"definableWords":["Christ"],"peopleInVerse":[]},"14":{"text":"Notwithstanding ye have well done, that ye did communicate with my affliction.","ref":"Philippians 4:14","synthesized":"Nevertheless, you have done well to share in my affliction.","sources":{"KJV":{"text":"Notwithstanding ye have well done, that ye did communicate with my affliction."},"BSB":{"text":"Nevertheless, you have done well to share in my affliction."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"Now ye Philippians know also, that in the beginning of the gospel, when I departed from Macedonia, no church communicated with me as concerning giving and receiving, but ye only.","ref":"Philippians 4:15","synthesized":"And as you Philippians know, in the early days of the gospel, when I left Macedonia, no church but you partnered with me in the matter of giving and receiving.","sources":{"KJV":{"text":"Now ye Philippians know also, that in the beginning of the gospel, when I departed from Macedonia, no church communicated with me as concerning giving and receiving, but ye only."},"BSB":{"text":"And as you Philippians know, in the early days of the gospel, when I left Macedonia, no church but you partnered with me in the matter of giving and receiving."}},"definableWords":["days","gospel","church"],"peopleInVerse":[]},"16":{"text":"For even in Thessalonica ye sent once and again unto my necessity.","ref":"Philippians 4:16","synthesized":"For even while I was in Thessalonica, you provided for my needs again and again.","sources":{"KJV":{"text":"For even in Thessalonica ye sent once and again unto my necessity."},"BSB":{"text":"For even while I was in Thessalonica, you provided for my needs again and again."}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"Not because I desire a gift: but I desire fruit that may abound to your account.","ref":"Philippians 4:17","synthesized":"Not that I am seeking a gift, but I am looking for the fruit that may be credited to your account.","sources":{"KJV":{"text":"Not because I desire a gift: but I desire fruit that may abound to your account."},"BSB":{"text":"Not that I am seeking a gift, but I am looking for the fruit that may be credited to your account."}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"But I have all, and abound: I am full, having received of Epaphroditus the things which were sent from you, an odour of a sweet smell, a sacrifice acceptable, wellpleasing to God.","ref":"Philippians 4:18","synthesized":"I have all I need and more, now that I have received your gifts from Epaphroditus. They are a fragrant offering, an acceptable sacrifice, well-pleasing to God.","sources":{"KJV":{"text":"But I have all, and abound: I am full, having received of Epaphroditus the things which were sent from you, an odour of a sweet smell, a sacrifice acceptable, wellpleasing to God."},"BSB":{"text":"I have all I need and more, now that I have received your gifts from Epaphroditus. They are a fragrant offering, an acceptable sacrifice, well-pleasing to God."}},"definableWords":["offering","sacrifice","God"],"peopleInVerse":[]},"19":{"text":"But my God shall supply all your need according to his riches in glory by Christ Jesus.","ref":"Philippians 4:19","synthesized":"And my God will supply all your needs according to His glorious riches in Christ Jesus.","sources":{"KJV":{"text":"But my God shall supply all your need according to his riches in glory by Christ Jesus."},"BSB":{"text":"And my God will supply all your needs according to His glorious riches in Christ Jesus."}},"definableWords":["God","Christ"],"peopleInVerse":["Jesus"]},"20":{"text":"Now unto God and our Father be glory for ever and ever. Amen.","ref":"Philippians 4:20","synthesized":"To our God and Father be glory forever and ever. Amen.","sources":{"KJV":{"text":"Now unto God and our Father be glory for ever and ever. Amen."},"BSB":{"text":"To our God and Father be glory forever and ever. Amen."}},"definableWords":["God","Father","glory"],"peopleInVerse":[]},"21":{"text":"Salute every saint in Christ Jesus. The brethren which are with me greet you.","ref":"Philippians 4:21","synthesized":"Greet all the saints in Christ Jesus.  The brothers who are with me send you greetings.","sources":{"KJV":{"text":"Salute every saint in Christ Jesus. The brethren which are with me greet you."},"BSB":{"text":"Greet all the saints in Christ Jesus.  The brothers who are with me send you greetings."}},"definableWords":["Christ"],"peopleInVerse":["Jesus"]},"22":{"text":"All the saints salute you, chiefly they that are of Caesar’s household.","ref":"Philippians 4:22","synthesized":"All the saints send you greetings, especially those from the household of Caesar.","sources":{"KJV":{"text":"All the saints salute you, chiefly they that are of Caesar’s household."},"BSB":{"text":"All the saints send you greetings, especially those from the household of Caesar."}},"definableWords":[],"peopleInVerse":[]},"23":{"text":"The grace of our Lord Jesus Christ be with you all. Amen.","ref":"Philippians 4:23","synthesized":"The grace of the Lord Jesus Christ be with your spirit.","sources":{"KJV":{"text":"The grace of our Lord Jesus Christ be with you all. Amen."},"BSB":{"text":"The grace of the Lord Jesus Christ be with your spirit."}},"definableWords":["grace","Lord","Christ","spirit"],"peopleInVerse":["Jesus"]}}}};